functions.example:
requirelib("sqlite");
var db = sqlite.open("user:/.appdata/myapp/data.sqlite");
db.exec("CREATE TABLE IF NOT EXISTS t (id INTEGER PRIMARY KEY, name TEXT)");
db.close();

requirelib("aimodel");
var reply = aimodel.chat("What is 2 + 2?");
sendResp(reply);

requirelib("aimodel");
var reply = aimodel.chatWithFile(
    "Describe this image.",
    "user:/Photos/holiday.jpg"
);
sendResp(reply);

requirelib("aimodel");
var resp = aimodel.request([
    { role: "system", content: "You are helpful." },
    { role: "user",   content: "Hi!" }
]);
sendResp(resp.choices[0].message.content);

requirelib("aimodel");
var parts = aimodel.fileParts(["user:/report.txt"]);
var resp = aimodel.request([{ role: "user", content: parts }]);
sendResp(resp.choices[0].message.content);

var msg = websocket.read(5000);
if (msg === false) { /* closed */ }
if (msg === null)  { /* timeout  */ }

var last = "";
websocket.onMessage = function(msg) {
    last = msg.data;
};
while (!websocket.isClosed()) {
    if (last !== "") {
        websocket.send("Echo: " + last);
        last = "";
    }
    delay(100);
}
